var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932: <color=#ffd34c>힐데</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932：<color=#ffd34c>ヒルデ</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932: <color=#ffd34c>Hilde</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932: <color=#ffd34c>希爾德</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기분이 안 좋아 보이는군.","JPN":"顔色が悪いな。","ENG":"You don't look so well.","TWN":"你看起來心情很糟呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무슨 나쁜 소식이라도 있나?","JPN":"何か悪い知らせでもあるのか？","ENG":"Do you have bad news?","TWN":"是有什麼壞消息嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"생색내긴 그렇지만 내 덕분에 당분간 자금 걱정은 없을 텐데?","JPN":"恩を着せるわけじゃないが、私のおかげで当分の間、資金の心配もいらないだろ？","ENG":"I don't want to brag, but I've given you enough money.","TWN":"雖然沒有要施恩圖報的意思，但多虧有我，你暫時不用擔心資金問題了不是嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"몇 년 동안 감감무소식이던 말괄량이 아가씨도 돌아왔고 말이야.","JPN":"数年間、何の音沙汰もなかったじゃじゃ馬娘も戻って来たことだしな。","ENG":"And your naughty Master has finally come back after years of silence.","TWN":"況且，幾年來一直音訊全無的野丫頭也回來了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"왜 그렇게 위궤양 도진 사람 같은 표정을 짓고 있는지 모르겠군.","JPN":"なのに、なぜそんなしんどそうな顔をしてるんだ？","ENG":"I can't figure out why you look like someone who has a stomach ulcer.","TWN":"真不懂為什麼你一副像是得了胃潰瘍的表情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......이게 다 누구 때문인데 아무것도 모른다는 듯이 가증스러운 표정을 짓고 계시는 거죠?","JPN":"……しらを切るのはやめてもらえますか？","ENG":"Are you serious? This is all because of you, and you're now acting like you don't know anything?","TWN":"……您也不想想是因為誰，還裝作什麼都不知道的樣子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"스승님이 돌아오신 거야 물론 축하할 일이지만 그분 성격상 앞으로 제가 수습해야 할 사건, 사고도 만만치 않을 겁니다.","JPN":"師匠が戻って来たのはもちろん喜ばしいことですが、あの方の性格を考える限り、私が後始末をする事件や事故も、かなり増えるので。","ENG":"Of course I'm glad that Master is back. But considering her personality, I'll have to cover up all the troubles she will cause.","TWN":"師父能回來了，這當然是件值得慶祝的事情。但是以她的個性，我之後得善後的事件、事故應該不少吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그것만 생각해도 <color=#ff3636>[DATA EXPUNGED]</color> 때 잃어버린 눈알이 지끈지끈 쑤시는 판인데 보안감찰 대상에 포함이라니.......","JPN":"それだけでも<color=#ff3636>[DATA EXPUNGED]</color>の時に失った目がズキズキ痛むのに、保安観察対象に含まれるなんて……","ENG":"The eye I lost during the <color=#ff3636>[DATA EXPUNGED]</color> aches just by thinking about it. And I now have perform a secret inspection on her?","TWN":"光是用想的，我在<color=#ff3636>[DATA_EXPUNGED]</color>時失去的眼球就開始發痛，更別說她竟然是在保護監察對象當中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"들키면 <color=#ff3636>[DATA EXPUNGED]</color> 님도 곱게 죽진 못할 겁니다.","JPN":"バレたら<color=#ff3636>[DATA EXPUNGED]</color>さんも、泣きをみることになりますよ。","ENG":"If Master finds out, you will meet a gruesome fate as well, <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"如果她被發現這件事，<color=#ff3636>[DATA_EXPUNGED]</color>可不只是死這麼簡單了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하하, 안 들키면 되는 거지, 안 들키면.","JPN":"はは、バレなければいいんだよ。バレなければ。","ENG":"Hah hah, it's okay as long as we don't get caught.","TWN":"哈哈，不被發現就行了，不被發現的話。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네 사정도 모르는 바는 아니지만 이것도 필요한 절차라서 말이야.","JPN":"君の事情もわかるが、これも必要な手続きなんだ。","ENG":"I understand your situation, but this is a necessary procedure.","TWN":"雖然我不知道你的處境，但這是個必要的程序。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그리고 그녀가 무슨 생각을 하는지 알아 둘 필요가 있다는 건 자네도 동의하지 않았나?","JPN":"彼女が何を考えているのか知る必要がある。これには君も同意するだろ？","ENG":"And didn't you agree that we need to know what she's thinking about?","TWN":"而且，我們需要知道她在想什麼，這你不是也同意了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......그건 그렇습니다만.","JPN":"……","ENG":"I did.","TWN":"……是沒錯啦。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좋아. 의견이 일치돼서 기쁘군.","JPN":"よし。意見が一致したようで嬉しいよ。","ENG":"Good. I'm glad we concur.","TWN":"很好，意見一致真是太好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 보고를 시작하지.","JPN":"では、報告を始めてくれ。","ENG":"Start the briefing then.","TWN":"那麼，開始報告吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Okay.","TWN":"……好的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"보고 대상은 현 코핀 컴퍼니 소속 제 1 소대 소대장 힐데입니다.","JPN":"報告の対象は現コフィンカンパニー所属、第1小隊の小隊長を務めているヒルデです。","ENG":"Our subject today is Hilde, commander of the Coffin Company's 1st squad.","TWN":"報告對象是現科芬公司所屬的第1小隊隊長希爾德。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"제 1 소대라...... 소대명은 당연히 <color=#ffd34c>그거</color>겠지?","JPN":"第1小隊か……小隊名は当然<color=#ffd34c>あれ</color>だろ？","ENG":"The 1st squad. I assume the name of her squad is <color=#ffd34c>that</color>?","TWN":"第1小隊……小隊名肯定是<color=#ffd34c>那個</color>吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"뭐...... 그렇죠.","JPN":"まあ……そうです。","ENG":"Well... Yes.","TWN":"這……是的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이럴 때 보면 의외로 집착적인 성격이란 말이야.","JPN":"君は意外と粘着質な面があるな。","ENG":"She is surprisingly obsessive when it comes to things like that.","TWN":"從這點來看，她的個性還真是執著呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"슬슬 지난 과거는 흘려 보낼 때도 된 것 같은데 말이지.","JPN":"そろそろ、過去は水に流してもいいんじゃないか。","ENG":"It's about time she let her past go.","TWN":"差不多也該放下過去的事情了吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......섬세한 성격이라고 해 두겠습니다.","JPN":"……繊細だと言ってください。","ENG":"Let's just say that she has a delicate personality.","TWN":"……我會說個性非常細膩。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어쨌든 걱정과는 다르게 복귀 후 첫 임무를 무사히 완료했습니다.","JPN":"とにかく、こちらの心配とは裏腹に、復帰後の初任務を無事に終えました。","ENG":"Anyway, despite our concerns, she successfully completed her first mission after returning.","TWN":"不管怎樣，一切都不像我擔心的那樣，回歸後的第一個任務順利完成了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"전후 사정을 감안해 봤을 때 구출 대상이 한 다섯 조각 정도로 나뉘어 올 수도 있다고 생각했는데.......","JPN":"前後の事情を踏まえると、救出対象がバラバラになって帰って来るかもしれないと思っていたのですが……","ENG":"Given the circumstances, I had expected her to bring back the rescued person in five different pieces...","TWN":"考慮到前後情況，我以為救援對象可能會被分成五份左右……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠! 크흠......!","JPN":"コホン！　コホン……！","ENG":"Ahem! Ahem!","TWN":"咳咳！咳咳……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"스승님도 성격이 많이 유해지신 모양이더군요.","JPN":"師匠もかなり丸くなったようですね。","ENG":"Master must have grown soft over the years.","TWN":"看來師父的個性也變仁慈了呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"어, 어쨌든...... 본인도 나름대로 귀환한 목적이 있을 테니 당분간 큰 사고를 치거나 하지는 않을 걸세.","JPN":"と、とにかく……彼女なりに帰還した目的があるはずだから、当分は事件を起こしたりはしないだろう。","ENG":"A-anyway... I'm sure she returned for a reason. I doubt that she wants to draw too much attention.","TWN":"總、總之……她本人這次回歸也有目的，暫時應該不會闖什麼大禍吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......저도 그랬으면 참 좋겠군요.","JPN":"……だといいのですが。","ENG":"I also hope that's the case.","TWN":"……我也真心希望是這樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좋아. 그럼 투자사의 무궁한 발전을 기대해 보도록 하지.","JPN":"よし。では、投資先の益々の発展を期待することにしよう。","ENG":"Good. I'm counting on the tremendous success of the company that I've invested in.","TWN":"很好，那我就期待這家公司更進一步的發展吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};